    },
    {
      "name": "multiple_document_uploads",
      "input": [
        {
          "document_id": "12345",
          "reviewer_id": "reviewer_1"
        },
        {
          "document_id": "67890",
          "reviewer_id": "reviewer_2"
        }
      ],
      "output": ["success", "success"],
      "args": [],
      "kwargs": {},
      "notes": "Tests the ability to handle multiple document uploads successfully."
    },
    {
      "name": "document_id_not_found",
      "input": {
        "document_id": "99999",
        "reviewer_id": "reviewer_1"
      },
      "output": "error: document ID not found",
      "args": [],
      "kwargs": {},
      "notes": "Tests the case where the document ID does not exist in the system."
    },
    {
      "name": "reviewer_not_authorized",
      "input": {
        "document_id": "12345",
        "reviewer_id": "unauthorized_reviewer"
      },
      "output": "error: reviewer not authorized",
      "args": [],
      "kwargs": {},
      "notes": "Tests the scenario where the reviewer is not authorized to access the document."
    },
    {
      "name": "large_document_upload",
      "input": {
        "document_id": "large_doc",
        "reviewer_id": "reviewer_1"
      },
      "output": "success",
